import React, { useState, useEffect } from 'react';
import { getHistory } from '../services/api';

export default function History() {
  const [history, setHistory] = useState([]);
  const [days, setDays] = useState(7);
  const [loading, setLoading] = useState(false);

  const load = async () => {
    setLoading(true);
    try {
      const data = await getHistory(days);
      setHistory(data);
    } catch (e) { console.error(e); }
    finally { setLoading(false); }
  };

  useEffect(() => { load(); }, [days]);

  const totalProfit = history.filter(d => d.type === 'DEAL_TYPE_SELL' || d.type === 'DEAL_TYPE_BUY')
    .reduce((sum, d) => sum + (d.profit || 0), 0);

  return (
    <div>
      <div className="page-header">
        <div className="page-title">Trade History</div>
        <div className="page-subtitle">Closed deals across MT4 & MT5</div>
      </div>

      {/* Period Selector */}
      <div style={{ display: 'flex', gap: 8, marginBottom: 24, alignItems: 'center' }}>
        {[1, 7, 14, 30].map(d => (
          <button
            key={d}
            className={`btn ${days === d ? 'btn-primary' : ''}`}
            onClick={() => setDays(d)}
            style={{ padding: '6px 14px', fontSize: 11 }}
          >
            {d === 1 ? 'Today' : `${d}D`}
          </button>
        ))}
        <div style={{ marginLeft: 'auto', fontSize: 12, color: 'var(--text2)' }}>
          Total P&L: <span className={totalProfit >= 0 ? 'profit' : 'loss'}>
            {totalProfit >= 0 ? '+' : ''}${totalProfit.toFixed(2)}
          </span>
        </div>
      </div>

      {loading ? (
        <div style={{ color: 'var(--text3)', padding: 40, textAlign: 'center' }}>Loading history...</div>
      ) : history.length === 0 ? (
        <div className="empty">
          <div className="empty-icon">◷</div>
          <div className="empty-text">No trade history for this period</div>
        </div>
      ) : (
        <div className="table-wrap">
          <table>
            <thead>
              <tr>
                <th>Time</th>
                <th>Symbol</th>
                <th>Platform</th>
                <th>Type</th>
                <th>Volume</th>
                <th>Price</th>
                <th>Commission</th>
                <th>Swap</th>
                <th>Profit</th>
              </tr>
            </thead>
            <tbody>
              {history.slice(0, 200).map((deal, i) => {
                const isBuy = deal.type === 'DEAL_TYPE_BUY';
                return (
                  <tr key={i}>
                    <td style={{ color: 'var(--text3)', fontSize: 11 }}>
                      {deal.time ? new Date(deal.time).toLocaleString() : '—'}
                    </td>
                    <td style={{ fontWeight: 600 }}>{deal.symbol || '—'}</td>
                    <td><span className={`badge badge-${deal.platform}`}>{deal.platform}</span></td>
                    <td>
                      {deal.symbol && (
                        <span className={`badge badge-${isBuy ? 'buy' : 'sell'}`}>
                          {isBuy ? 'BUY' : 'SELL'}
                        </span>
                      )}
                    </td>
                    <td>{deal.volume || '—'}</td>
                    <td style={{ fontFamily: 'var(--font-mono)' }}>{deal.price || '—'}</td>
                    <td style={{ color: deal.commission < 0 ? 'var(--red)' : 'var(--text3)' }}>
                      {deal.commission?.toFixed(2) ?? '0.00'}
                    </td>
                    <td style={{ color: 'var(--text3)' }}>{deal.swap?.toFixed(2) ?? '0.00'}</td>
                    <td className={(deal.profit || 0) >= 0 ? 'profit' : 'loss'}>
                      {(deal.profit || 0) >= 0 ? '+' : ''}${(deal.profit || 0).toFixed(2)}
                    </td>
                  </tr>
                );
              })}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}
